import{_ as r,I as o,o as i,c,j as t,a,J as d,w as l,a6 as h}from"./chunks/framework.CgU7tkAh.js";const _=JSON.parse('{"title":"How Intake24 stores and calculates nutrient data","description":"","frontmatter":{},"headers":[],"relativePath":"admin/foods/nutrient-data-model.md","filePath":"admin/foods/nutrient-data-model.md"}'),p={name:"admin/foods/nutrient-data-model.md"};function u(m,e,f,b,g,v){const n=o("MermaidDiagram"),s=o("ClientOnly");return i(),c("div",null,[e[0]||(e[0]=t("h1",{id:"how-intake24-stores-and-calculates-nutrient-data",tabindex:"-1"},[a("How Intake24 stores and calculates nutrient data "),t("a",{class:"header-anchor",href:"#how-intake24-stores-and-calculates-nutrient-data","aria-label":"Permalink to “How Intake24 stores and calculates nutrient data”"},"​")],-1)),e[1]||(e[1]=t("p",null,"Intake24 keeps current food composition data and submitted survey data in different databases. The foods database is the current source. A submitted recall is a historical snapshot.",-1)),e[2]||(e[2]=t("p",null,"This page explains the nutrient data model by following one pizza from food selection to a stored nutrient value.",-1)),e[3]||(e[3]=t("h2",{id:"the-model-in-one-minute",tabindex:"-1"},[a("The model in one minute "),t("a",{class:"header-anchor",href:"#the-model-in-one-minute","aria-label":"Permalink to “The model in one minute”"},"​")],-1)),e[4]||(e[4]=t("p",null,"A food selected in a recall does not contain nutrient values itself. Its locale and food code identify a locale food, which is mapped to a food composition record containing values per 100 g.",-1)),e[5]||(e[5]=t("p",null,"Intake24 applies the consumed portion weight to those values. On submission, it stores the result as a snapshot so later changes to the foods database do not silently rewrite research data.",-1)),d(s,null,{default:l(()=>[d(n,{graph:"flowchart%20LR%0A%20%20A%5B%22Locale%20food%3Cbr%2F%3EUK_V3_2023%20%2F%20CTTB%22%5D%0A%20%20B%5B%22Food%20composition%20record%3Cbr%2F%3EUK_NDB_3_TEST%20%2F%2010026%22%5D%0A%20%20C%5B%22Value%20per%20100%20g%3Cbr%2F%3E260.0%20kcal%22%5D%0A%20%20D%5B%22Portion%20calculation%3Cbr%2F%3E260.0%20x%20184.25%20%2F%20100%22%5D%0A%20%20E%5B%22Submitted%20snapshot%3Cbr%2F%3E479.05%20kcal%22%5D%0A%0A%20%20A%20--%3E%7Cfood%20mapping%7C%20B%0A%20%20B%20--%3E%20C%0A%20%20C%20--%3E%7Capply%20consumed%20weight%7C%20D%0A%20%20D%20--%3E%20E%0A"})]),_:1}),e[6]||(e[6]=h(`<p>The first three steps use current source data. The final step is stored with the submitted recall.</p><h2 id="follow-one-pizza-through-intake24" tabindex="-1">Follow one pizza through Intake24 <a class="header-anchor" href="#follow-one-pizza-through-intake24" aria-label="Permalink to “Follow one pizza through Intake24”">​</a></h2><h3 id="_1-identify-the-locale-food" tabindex="-1">1. Identify the locale food <a class="header-anchor" href="#_1-identify-the-locale-food" aria-label="Permalink to “1. Identify the locale food”">​</a></h3><p>In locale <code>UK_V3_2023</code>, food code <code>CTTB</code> means <strong>Cheese and tomato pizza</strong>. A food code is unique within a locale, not across the whole Intake24 system.</p><p>The pair <code>UK_V3_2023 / CTTB</code> is therefore the reliable identity used to find this food in the foods database.</p><h3 id="_2-select-its-food-composition-record" tabindex="-1">2. Select its food composition record <a class="header-anchor" href="#_2-select-its-food-composition-record" aria-label="Permalink to “2. Select its food composition record”">​</a></h3><p>The pizza&#39;s food mapping selects <code>UK_NDB_3_TEST / 10026</code>, named <strong>CHEESE AND TOMATO PIZZA ANY BASE RETAIL</strong>.</p><p>This page calls it a <strong>food composition record</strong>. In the database schema, the same concept is a <strong>nutrient table record</strong>.</p><p>The record supplies nutrient values per 100 g:</p><table tabindex="0"><thead><tr><th>Nutrient type ID</th><th>Nutrient</th><th>Unit</th><th style="text-align:right;">Value per 100 g</th></tr></thead><tbody><tr><td><code>1</code></td><td>Energy</td><td>kcal</td><td style="text-align:right;"><code>260.0</code></td></tr><tr><td><code>2</code></td><td>Energy</td><td>kJ</td><td style="text-align:right;"><code>1097.0</code></td></tr><tr><td><code>11</code></td><td>Protein</td><td>g</td><td style="text-align:right;"><code>11.3</code></td></tr><tr><td><code>13</code></td><td>Carbohydrate</td><td>g</td><td style="text-align:right;"><code>36.0</code></td></tr><tr><td><code>49</code></td><td>Fat</td><td>g</td><td style="text-align:right;"><code>8.9</code></td></tr></tbody></table><p>Nutrient type IDs give variables a stable identity. For example, type <code>1</code> means Energy in kcal and determines both the unit and the key used in submitted nutrient JSON.</p><h3 id="_3-apply-the-consumed-portion" tabindex="-1">3. Apply the consumed portion <a class="header-anchor" href="#_3-apply-the-consumed-portion" aria-label="Permalink to “3. Apply the consumed portion”">​</a></h3><p>The composition record describes 100 g, but the participant consumed about <code>184.25 g</code>. Intake24 calculates each portion-level value with the same relationship:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>submitted nutrient value = value per 100 g * consumed weight / 100</span></span>
<span class="line"><span>479.05 kcal = 260.0 kcal * 184.25 g / 100 g</span></span></code></pre></div><p>The portion data can include serving and leftover weights. The resulting consumed weight is what scales the source values.</p><h3 id="_4-store-the-submitted-snapshot" tabindex="-1">4. Store the submitted snapshot <a class="header-anchor" href="#_4-store-the-submitted-snapshot" aria-label="Permalink to “4. Store the submitted snapshot”">​</a></h3><p>When the recall is submitted, Intake24 stores nutrient type <code>1</code> with a portion-level value of about <code>479.05</code>. It does not store <code>260.0</code>, because that is the source value for 100 g.</p><p>The submitted food also keeps its locale, food code and names, composition record reference, metadata fields, and portion data.</p><div class="tip custom-block"><p class="custom-block-title">Developer note</p><p>Submitted foods are rows in <code>survey_submission_foods</code>. Relevant columns include <code>locale</code>, <code>code</code>, <code>nutrient_table_id</code>, <code>nutrient_table_code</code>, <code>fields</code>, <code>nutrients</code>, and <code>portion_size</code>.</p></div><h2 id="current-source-data-and-submitted-snapshots" tabindex="-1">Current source data and submitted snapshots <a class="header-anchor" href="#current-source-data-and-submitted-snapshots" aria-label="Permalink to “Current source data and submitted snapshots”">​</a></h2><p>The foods database answers: <strong>What food and composition data should Intake24 use now?</strong></p><p>The system database answers: <strong>What food, portion, and calculated nutrients were saved with this submission?</strong></p><table tabindex="0"><thead><tr><th>Current foods database</th><th>Submitted system database</th></tr></thead><tbody><tr><td>Locale food name and code</td><td>Saved locale, food code, and names</td></tr><tr><td>Current food-to-composition mapping</td><td>Saved composition table ID and record code</td></tr><tr><td>Current values per 100 g</td><td>Saved nutrient values for the consumed portion</td></tr><tr><td>Current composition metadata</td><td>Saved <code>fields</code> JSON</td></tr><tr><td>Used by current and future recalls</td><td>Preserved as part of the submitted recall</td></tr></tbody></table><p>This separation explains why a submitted food can retain an old name, composition record, or nutrient value after an administrator changes the foods database.</p><h2 id="how-csv-import-differs-from-food-mapping" tabindex="-1">How CSV import differs from food mapping <a class="header-anchor" href="#how-csv-import-differs-from-food-mapping" aria-label="Permalink to “How CSV import differs from food mapping”">​</a></h2><p>Importing food composition data and mapping locale foods are separate jobs.</p><ol><li><strong>Import Nutrient data/ nutrient mapping</strong> reads a source CSV (data) and its column configuration (mapping). It creates or updates composition records, metadata fields, and nutrient values per 100 g.</li><li><strong>Food mapping</strong> links a locale food such as <code>UK_V3_2023 / CTTB</code> to one of those imported composition records.</li></ol><p>Import therefore answers <strong>what does this composition record contain?</strong> Mapping answers <strong>which composition record should this locale food use?</strong></p><p>Importing a composition table does not, by itself, decide which locale food should use each record.</p><div class="tip custom-block"><p class="custom-block-title">Developer note</p><p>Composition import writes <code>nutrient_table_records</code>, <code>nutrient_table_record_fields</code>, and <code>nutrient_table_record_nutrients</code>. Food mapping writes the association in <code>foods_nutrients</code>.</p></div><h2 id="what-administrative-changes-affect" tabindex="-1">What administrative changes affect <a class="header-anchor" href="#what-administrative-changes-affect" aria-label="Permalink to “What administrative changes affect”">​</a></h2><table tabindex="0"><thead><tr><th>Administrative change</th><th>Current and future recalls</th><th>Already submitted recalls</th></tr></thead><tbody><tr><td>Change a food name</td><td>Search and display use the new name</td><td>Saved names remain unchanged</td></tr><tr><td>Correct a value per 100 g</td><td>New calculations use the corrected value</td><td>Saved portion values remain unchanged until recalculation</td></tr><tr><td>Add or remove a nutrient or metadata field</td><td>New calculations use the current record structure</td><td>Saved JSON structure remains unchanged until a full sync</td></tr><tr><td>Remap a locale food to different nutrient table</td><td>New calculations use the latest composition record</td><td>Saved mapping remains unchanged unless recalculation replaces it</td></tr></tbody></table><p>Changing source data never changes a submitted recall by itself.</p><h2 id="database-table-reference" tabindex="-1">Database table reference <a class="header-anchor" href="#database-table-reference" aria-label="Permalink to “Database table reference”">​</a></h2><p>This reference connects the reader-facing concepts above to their implementation names.</p><table tabindex="0"><thead><tr><th>Concept</th><th>Table or field</th><th>Purpose</th></tr></thead><tbody><tr><td>Locale food</td><td><code>foods</code></td><td>Stores the food code and names within a locale</td></tr><tr><td>Food mapping</td><td><code>foods_nutrients</code></td><td>Associates a locale food with a composition record</td></tr><tr><td>Composition table</td><td><code>nutrient_tables</code></td><td>Groups composition records from one source</td></tr><tr><td>Food composition record</td><td><code>nutrient_table_records</code></td><td>Stores the source record ID and description</td></tr><tr><td>Composition metadata</td><td><code>nutrient_table_record_fields</code></td><td>Stores extra values such as <code>sub_group_code</code></td></tr><tr><td>Values per 100 g</td><td><code>nutrient_table_record_nutrients</code></td><td>Stores one value per nutrient type for a record</td></tr><tr><td>Nutrient variable</td><td><code>nutrient_types</code></td><td>Defines the nutrient identity and unit</td></tr><tr><td>Nutrient unit</td><td><code>nutrient_units</code></td><td>Defines symbols such as <code>kcal</code>, <code>kJ</code>, or <code>g</code></td></tr><tr><td>Submitted snapshot</td><td><code>survey_submission_foods</code></td><td>Stores the selected food, portion, fields, and calculated nutrients</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Developer note</p><p><code>survey_submission_foods.parent_id</code> is a self-link. It supports child rows such as recipe-builder components or split foods. Each child keeps its own identity, portion data, and nutrient snapshot.</p></div><h2 id="recalculation-and-per-food-locales" tabindex="-1">Recalculation and per-food locales <a class="header-anchor" href="#recalculation-and-per-food-locales" aria-label="Permalink to “Recalculation and per-food locales”">​</a></h2><p>Submitted snapshots do not update automatically. The <code>SurveyNutrientsRecalculation</code> job can refresh their nutrient values and, when requested, replace the saved composition reference with the latest food mapping.</p><p>Use <code>values-only</code> to preserve the original composition reference. Use <code>values-and-codes</code> only when submissions should follow the latest mapping.</p><p>Set <code>syncFields: true</code> when the snapshot&#39;s nutrient and metadata keys should fully match the chosen composition record. Leave it <code>false</code> to update only values for keys already stored.</p><p>The choice affects data provenance. See <a href="/admin/surveys/survey-nutrients-recalculation-job">SurveyNutrientsRecalculation job details</a> for modes, structural syncing, edge cases, and operational safeguards.</p><div class="warning custom-block"><p class="custom-block-title">Do not assume one locale per submission</p><p>Every submitted food stores its own <code>locale</code>. Recalculation must resolve a food from that row&#39;s <code>locale + code</code>, because the same code can have different meanings or mappings in different locales.</p></div><h2 id="key-terms" tabindex="-1">Key terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to “Key terms”">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Meaning</th><th>Pizza example</th></tr></thead><tbody><tr><td>Locale</td><td>The food database context in which a food code is unique</td><td><code>UK_V3_2023</code></td></tr><tr><td>Food code</td><td>A stable identifier for a food within a locale</td><td><code>CTTB</code></td></tr><tr><td>Food composition record</td><td>A source record containing metadata and nutrient values per 100 g</td><td><code>UK_NDB_3_TEST / 10026</code></td></tr><tr><td>Nutrient type</td><td>A stable nutrient variable with a defined unit</td><td><code>1</code> = Energy in kcal</td></tr><tr><td>Value per 100 g</td><td>The source amount before portion weight is applied</td><td><code>260.0 kcal</code></td></tr><tr><td>Consumed weight</td><td>The portion amount after serving and leftovers are interpreted</td><td>about <code>184.25 g</code></td></tr><tr><td>Submitted nutrient snapshot</td><td>The calculated portion-level values saved with one submitted food</td><td>type <code>1</code> = <code>479.05 kcal</code></td></tr><tr><td>Recalculation</td><td>An explicit job that refreshes submitted snapshots from source composition data</td><td><code>values-only</code> or <code>values-and-codes</code></td></tr></tbody></table>`,45))])}const k=r(p,[["render",u]]);export{_ as __pageData,k as default};
